#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        qsort(a, n, sizeof(int), compare);
        int count = 1;
        for (int i = 1; i < n; i++) {
            if (a[i] == a[i - 1]) {
                count++;
            } else {
                long long fact = 1;
                for (int j = 2; j <= count; j++) {
                    fact = (fact * j) % (1000000007);
                }
                count = 1;
            }
        }
        long long fact = 1;
        for (int j = 2; j <= count; j++) {
