        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            Arrays.sort(a);
            int count = 1;
            long fact = 1;
            for (int i = 1; i < n; i++) {
                if (a[i] == a[i - 1]) {
                    count++;
                } else {
                    for (int j = 2; j <= count; j++) {
                        fact = (fact * j) % (1000000007);
                    }
                    count = 1;
                }
            }
